 */
export function resolveLensFilter(
  viewElem: { defaultLens?: ViewLensMode } | null | undefined,
): (elem: Element) => 'foreground' | 'ghost' {
  const lens: ViewLensMode = viewElem?.defaultLens ?? 'show_all';

  if (lens === 'show_all') {
    return () => 'foreground';
